    style.setProperty("--input", "rgba(255,255,255,0.08)");
  } else {
    style.setProperty("--secondary", "rgba(0,0,0,0.04)");
    style.setProperty("--secondary-foreground", colors.foreground);
    style.setProperty("--muted", "rgba(0,0,0,0.04)");
    style.setProperty("--muted-foreground", "rgba(0,0,0,0.45)");
    style.setProperty("--accent", "rgba(0,0,0,0.04)");
    style.setProperty("--accent-foreground", colors.foreground);
    style.setProperty("--border", "rgba(0,0,0,0.08)");
    style.setProperty("--input", "rgba(0,0,0,0.10)");
  }

  // Theme-specific extras
  style.setProperty("--theme-sidebar", colors.sidebar);
  style.setProperty("--theme-editor", colors.editor);
  style.setProperty("--theme-terminal", colors.terminal);
  style.setProperty("--theme-status-bar", colors.statusBar);

  // Typography
  style.setProperty("--theme-font-family", theme.fontFamily);
  style.setProperty("--theme-font-size", `${theme.fontSize}px`);

  // Dark class
  applyDarkClass(isDark);
}

/** Apply a custom theme (or clear overrides when the id is invalid). */
function applyCustomTheme(themeId: string) {
  const theme = getTheme(themeId);
  if (!theme) {
    clearThemeProperties();
    return;
  }
  applyCustomThemeProperties(theme);
}

/**
 * Apply the appearance mode (light / dark / system) to the DOM.
 * This is only used as a fallback when no custom theme is active.
 */
function applyAppearanceMode(mode: AppearanceMode) {
  const isDark = mode === "dark" || (mode === "system" && getSystemDark());
  applyDarkClass(isDark);
}

// ---------------------------------------------------------------------------
// Initialise on module load (prevents theme flash)
// ---------------------------------------------------------------------------

const initialThemeId = getStoredCustomThemeId();
const initialTheme = getTheme(initialThemeId);

if (initialTheme) {
  applyCustomThemeProperties(initialTheme);
} else {
  applyAppearanceMode(getStoredAppearanceMode());
}

// ---------------------------------------------------------------------------
// External store plumbing
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const appearanceMode = getStoredAppearanceMode();
  const systemDark = appearanceMode === "system" ? getSystemDark() : false;
  const customThemeId = getStoredCustomThemeId();

  if (
    lastSnapshot &&
    lastSnapshot.appearanceMode === appearanceMode &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.customThemeId === customThemeId
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { appearanceMode, systemDark, customThemeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    const mode = getStoredAppearanceMode();
    if (mode === "system") {
      suppressTransitions(() => {
        const themeId = getStoredCustomThemeId();
        const theme = getTheme(themeId);
        if (theme) {
          applyCustomThemeProperties(theme);
        } else {
          applyAppearanceMode("system");
        }
      });
    }
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY || e.key === CUSTOM_THEME_STORAGE_KEY) {
      suppressTransitions(() => {
        applyCustomTheme(getStoredCustomThemeId());
      });
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Public hook
// ---------------------------------------------------------------------------

/** @deprecated Use `setCustomTheme` for full theme switching. */
type Theme_COMPAT = "light" | "dark" | "system";

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const resolvedTheme: "light" | "dark" =
    snapshot.appearanceMode === "system"
      ? snapshot.systemDark
        ? "dark"
        : "light"
      : snapshot.appearanceMode;

  // ---- backward-compatible appearance mode setter ----

  const setTheme = useCallback((next: Theme_COMPAT) => {
    localStorage.setItem(STORAGE_KEY, next);

    // Keep custom theme in sync: if the current theme's dark/light nature
    // conflicts with the requested mode, swap to the default matching theme.
    const isDark = next === "dark" || (next === "system" && getSystemDark());
    const current = getTheme(getStoredCustomThemeId());
    if (current && current.isDark !== isDark) {
      const fallbackId = isDark ? "t3-dark" : "t3-light";
      localStorage.setItem(CUSTOM_THEME_STORAGE_KEY, fallbackId);
    }

    suppressTransitions(() => {
      applyCustomTheme(getStoredCustomThemeId());
    });
    emitChange();
  }, []);

  // ---- custom theme API ----

  const customTheme: Theme =
    getTheme(snapshot.customThemeId) ?? getTheme(DEFAULT_THEME_ID)!;

  const availableThemes = listThemes();

  const setCustomTheme = useCallback((id: string) => {
    const theme = getTheme(id);
    if (!theme) return;

    localStorage.setItem(CUSTOM_THEME_STORAGE_KEY, id);
    // Keep appearance mode in sync
    const mode: AppearanceMode = theme.isDark ? "dark" : "light";
    localStorage.setItem(STORAGE_KEY, mode);

    suppressTransitions(() => {
      applyCustomThemeProperties(theme);
    });
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyCustomTheme(snapshot.customThemeId);
  }, [snapshot.customThemeId]);

  return {
    /** Appearance mode string – kept for backward compatibility. */
    theme: snapshot.appearanceMode,
    /** Set the appearance mode – kept for backward compatibility. */
    setTheme,
    /** Resolved to "light" or "dark". */
    resolvedTheme,
    /** The active custom `Theme` object from `@t3tools/shared/themes`. */
    customTheme,
    /** Switch to a different theme by id. */
    setCustomTheme,
    /** All available themes. */
    availableThemes,
  } as const;
}

