import type { Theme } from "@t3tools/shared/themes";

import { useTheme } from "../hooks/useTheme";

/**
 * A color swatch strip showing the four key colors of a theme.
 */
function ThemeSwatches({ colors }: { colors: Theme["colors"] }) {
  const swatches = [
    { color: colors.background, label: "Background" },
    { color: colors.foreground, label: "Foreground" },
    { color: colors.accent, label: "Accent" },
    { color: colors.sidebar, label: "Sidebar" },
  ];

  return (
    <div className="flex gap-1">
      {swatches.map((s) => (
        <div
          key={s.label}
          title={s.label}
          className="size-4 rounded-sm border border-black/10 dark:border-white/10"
          style={{ backgroundColor: s.color }}
        />
      ))}
    </div>
  );
}

/**
 * Displays all available themes as selectable cards with color swatches.
 */
export function ThemeSelector() {
  const { customTheme, setCustomTheme, availableThemes } = useTheme();

  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((t) => {
        const selected = customTheme.id === t.id;

        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={[
              "flex flex-col items-start gap-2 rounded-lg border px-3 py-2.5 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            ].join(" ")}
            onClick={() => setCustomTheme(t.id)}
          >
            <ThemeSwatches colors={t.colors} />

            <div className="flex w-full items-center justify-between gap-2">
              <span className="text-sm font-medium">{t.name}</span>

              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

