/** Color palette for a T3 Code theme. */
export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

/** A complete theme definition for T3 Code. */
export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly isDark: boolean;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

export const DEFAULT_THEME_ID = "t3-dark";

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "#0c0c0d",
      foreground: "#f5f5f5",
      accent: "#5b8def",
      sidebar: "#111113",
      editor: "#0c0c0d",
      terminal: "#09090b",
      statusBar: "#111113",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "#2563eb",
      sidebar: "#f8f8fa",
      editor: "#ffffff",
      terminal: "#f4f4f6",
      statusBar: "#f0f0f2",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
    colors: {
      background: "#020217",
      foreground: "#e0e0ff",
      accent: "#818cf8",
      sidebar: "#0a0a23",
      editor: "#020217",
      terminal: "#010114",
      statusBar: "#0a0a23",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
];

const themeMap = new Map<string, Theme>(
  BUILT_IN_THEMES.map((theme) => [theme.id, theme]),
);

/** Look up a theme by id. Returns `undefined` when the id is unknown. */
export function getTheme(id: string): Theme | undefined {
  return themeMap.get(id);
}

/** Return every built-in theme. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

